import { invoke } from "@tauri-apps/api/core";
import { openUrl } from "@tauri-apps/plugin-opener";
import { useEffect, useRef, useState } from "react";

type AssetType = "a_share" | "hk_stock" | "fund";
type Holding = {
  security_id: string; name: string; symbol: string; asset_type: AssetType;
  invested_amount_cny: string | null; bought_on: string | null; quantity: string | null;
  price: number | null; change_percent: number | null; trade_date: string | null;
  valuation_status: string; source: string; estimated_profit_cny: number | null;
  estimated_profit_percent: number | null; profit_basis: string | null; profit_reason: string | null;
};
type HoldingEntry = { holding_id: string; security_id: string; asset_type: AssetType; invested_amount_cny: string; bought_on: string; revision_number: string; estimated_profit_cny: number | null; estimated_profit_percent: number | null; profit_reason: string | null };
type Material = { material_id: string; security_id: string; material_type: string; title: string; published_at: string; source_name: string; source_url: string; excerpt: string };
type Note = { note_id: string; security_id: string; body: string; created_at: string; updated_at?: string; source_title: string | null; source_url: string | null; quoted_text: string | null };
type FinancialPeriod = { period: string; period_label: string; roe: number | null; gross_margin: number | null; debt_asset_ratio: number | null; operating_cash_flow: number | null; free_cash_flow: number | null };
type Financials = { periods: FinancialPeriod[]; source: string; cutoff_date: string; free_cash_flow_note: string };
type FundProfile = { symbol: string; name: string; cutoff_date: string; source: string; nav_history: Array<{ date: string; nav: number; change_percent: number | null; event: string | null }>; returns: Record<string, number>; fees: { management_rate: string | null; custodian_rate: string | null; sales_service_rate: string | null }; managers: Array<{ name: string; work_time: string; managed_scale: string; score: number | null; tenure_return_percent: number | null }> };
type Thesis = { thesis_id: string; body: string; review_due_on: string | null; revision_number: number };
type Workspace = { thesis: Thesis | null; materials: Material[]; notes: Note[]; financials: Financials | null; fund: FundProfile | null; timeline: { items: Array<{ event_id: string; summary: string; occurred_at: string }>; total_count: number } };
type Market = {
  indices?: { date: string; source: string; rows: Array<{ code: string; name: string; close: number; change_percent: number | null }> };
  lhb?: { date: string; source: string; rows: Array<{ symbol: string; name: string; change_percent: number | null; buy_amount: number | null; sell_amount: number | null; net_amount: number | null; reason: string }> };
  industry_flow?: { date: string; source: string; inbound: Array<{ code: string; name: string; change_percent: number | null; net_amount: number | null; net_ratio: number | null }>; outbound: Array<{ code: string; name: string; change_percent: number | null; net_amount: number | null; net_ratio: number | null }> };
};
type Bootstrap = { mode: "vault"; report_as_of: string | null; refreshed_at: string | null; archive_coverage: { target_date: string | null; current: number; total: number; stale: number }; disclaimer: string; holdings: Holding[]; holding_entries: HoldingEntry[]; market: Market };
type HoldingDraft = { row_id: string; symbol: string; asset_type: AssetType; invested_amount_cny: string; bought_on: string };
type DeleteRequest = { kind: "holding"; entry: HoldingEntry; label: string } | { kind: "note"; note: Note; label: string };

const navItems = [
  { key: "today", label: "今日复盘" }, { key: "market", label: "市场盘后" },
  { key: "portfolio", label: "持仓账本" }, { key: "security", label: "证券资料" },
  { key: "research", label: "投资笔记" }, { key: "data", label: "数据与备份" },
];
async function api<T>(url: string, options?: RequestInit): Promise<T> { const response = await fetch(url, options); if (!response.ok) { const body = await response.json().catch(() => ({})); throw new Error(body.detail || `请求失败（${response.status}）`); } return response.json(); }
const money = (value: number | null) => value === null ? "—" : `¥${value.toLocaleString("zh-CN", { maximumFractionDigits: 2 })}`;
const amountYi = (value: number | null) => value === null ? "—" : `${(value / 100_000_000).toLocaleString("zh-CN", { maximumFractionDigits: 2 })}亿`;
const percent = (value: number | null) => value === null ? "—" : `${value >= 0 ? "+" : ""}${value.toFixed(2)}%`;
const day = (value: string | null) => value ? value.slice(0, 10) : "尚未归档";
const assetLabel = (value: AssetType) => ({ a_share: "A股", hk_stock: "港股", fund: "基金" })[value];
const invested = (value: string | null) => value === null ? "—" : `¥${Number(value).toLocaleString("zh-CN", { maximumFractionDigits: 2 })}`;
const symbolOf = (securityId: string) => securityId.split(":")[2];
const tone = (value: number | null) => value === null ? "" : value >= 0 ? "up" : "down";
const newDraft = (): HoldingDraft => ({ row_id: globalThis.crypto?.randomUUID?.() ?? `${Date.now()}-${Math.random()}`, symbol: "", asset_type: "a_share", invested_amount_cny: "", bought_on: "" });
const followSource = (event: React.MouseEvent<HTMLAnchorElement>, url: string) => { if ((window as unknown as { __TAURI_INTERNALS__?: object }).__TAURI_INTERNALS__) { event.preventDefault(); void openUrl(url); } };

function Tag({ children, tone = "neutral" }: { children: React.ReactNode; tone?: "neutral" | "up" | "down" | "warning" }) { return <span className={`tag tag-${tone}`}>{children}</span>; }
function Card({ title, children, action, className = "" }: { title: string; children: React.ReactNode; action?: React.ReactNode; className?: string }) { return <section className={`card ${className}`}><div className="card-header"><h2>{title}</h2>{action && <div className="card-action">{action}</div>}</div><div className="card-body">{children}</div></section>; }
function PageHeader({ eyebrow, title, description }: { eyebrow: string; title: string; description: string }) { return <header className="page-header"><div className="page-eyebrow">{eyebrow}</div><h1>{title}</h1><p>{description}</p></header>; }
const cardLimitForWidth = (width: number) => width >= 960 ? 12 : width >= 720 ? 8 : width >= 540 ? 4 : 3;
const replaceTrailingCards = (current: string[], selected: string[], limit: number) => { const promoted = [...new Set(selected)].slice(0, limit); const keep = current.filter((id) => !promoted.includes(id)).slice(0, Math.max(0, limit - promoted.length)); return [...keep, ...promoted]; };

function HoldingEditor({ save, cancel, initialRows, editing = false }: { save: (rows: HoldingDraft[]) => Promise<void>; cancel: () => void; initialRows?: HoldingDraft[]; editing?: boolean }) {
  const [rows, setRows] = useState<HoldingDraft[]>(initialRows?.length ? initialRows : [newDraft()]); const [errors, setErrors] = useState<Record<string, string>>({}); const today = new Date().toISOString().slice(0, 10);
  const update = (rowId: string, field: keyof HoldingDraft, value: string) => { setRows((current) => current.map((row) => row.row_id === rowId ? { ...row, [field]: value } : row)); setErrors((current) => { const next = { ...current }; delete next[`${rowId}:${field}`]; return next; }); };
  const submit = async (event: React.FormEvent) => { event.preventDefault(); const next: Record<string, string> = {}; rows.forEach((row) => { const symbol = row.symbol.trim().toUpperCase(); if (!symbol) next[`${row.row_id}:symbol`] = "请填写证券代码"; else if (["a_share", "fund"].includes(row.asset_type) && !/^\d{6}$/.test(symbol)) next[`${row.row_id}:symbol`] = "A股和基金代码为6位数字"; else if (row.asset_type === "hk_stock" && !/^\d{1,5}$/.test(symbol)) next[`${row.row_id}:symbol`] = "港股代码为1至5位数字"; if (!row.invested_amount_cny || Number(row.invested_amount_cny) <= 0) next[`${row.row_id}:invested_amount_cny`] = "请填写大于0的人民币金额"; if (!row.bought_on) next[`${row.row_id}:bought_on`] = "请选择买入日期"; else if (row.bought_on > today) next[`${row.row_id}:bought_on`] = "买入日期不能晚于今天"; }); setErrors(next); if (!Object.keys(next).length) await save(rows.map((row) => ({ ...row, symbol: row.symbol.trim().toUpperCase() }))); };
  return <><PageHeader eyebrow={editing ? "修订持仓" : "持仓录入"} title={editing ? "编辑持仓记录" : "添加我的持仓"} description="金额只按人民币记录；盈亏使用买入日收盘价或基金净值估算，不推算持仓数量。" /><form className="holding-editor" onSubmit={submit} noValidate><div className="holding-editor-head"><div><strong>{editing ? "核对修订内容" : "持仓清单"}</strong><span>代码、类型、金额、日期均为必填</span></div><button type="button" className="text-button" onClick={cancel}>返回</button></div><div className="holding-entry-list">{rows.map((row, index) => <fieldset className="holding-entry-row" key={row.row_id}><legend>第 {index + 1} 行</legend><label><span>代码 <b>*</b></span><input className="mono" value={row.symbol} onChange={(event) => update(row.row_id, "symbol", event.target.value)} placeholder="600519" aria-invalid={Boolean(errors[`${row.row_id}:symbol`])} />{errors[`${row.row_id}:symbol`] && <small>{errors[`${row.row_id}:symbol`]}</small>}</label><label><span>类型 <b>*</b></span><select value={row.asset_type} onChange={(event) => update(row.row_id, "asset_type", event.target.value as AssetType)}><option value="a_share">A股</option><option value="hk_stock">港股</option><option value="fund">基金</option></select></label><label><span>买入金额（人民币）<b>*</b></span><input className="mono" type="number" min="0.01" step="0.01" value={row.invested_amount_cny} onChange={(event) => update(row.row_id, "invested_amount_cny", event.target.value)} aria-invalid={Boolean(errors[`${row.row_id}:invested_amount_cny`])} />{errors[`${row.row_id}:invested_amount_cny`] && <small>{errors[`${row.row_id}:invested_amount_cny`]}</small>}</label><label><span>买入日期 <b>*</b></span><input className="mono" type="date" max={today} value={row.bought_on} onChange={(event) => update(row.row_id, "bought_on", event.target.value)} aria-invalid={Boolean(errors[`${row.row_id}:bought_on`])} />{errors[`${row.row_id}:bought_on`] && <small>{errors[`${row.row_id}:bought_on`]}</small>}</label>{!editing && rows.length > 1 && <div className="holding-entry-remove"><span>本行操作</span><button type="button" className="text-button danger-text" onClick={() => setRows((current) => current.filter((item) => item.row_id !== row.row_id))} aria-label={`删除第 ${index + 1} 行`}>删除本行</button></div>}</fieldset>)}</div><div className="holding-editor-actions">{!editing && <button type="button" className="secondary" disabled={rows.length >= 100} onClick={() => setRows((current) => [...current, newDraft()])}>＋ 添加下一行</button>}<button type="submit">{editing ? "保存修订" : "确认并保存"}</button></div></form></>;
}

function HoldingPicker({ holdings, visibleIds, limit, cancel, apply }: { holdings: Holding[]; visibleIds: string[]; limit: number; cancel: () => void; apply: (ids: string[]) => void }) {
  const [selected, setSelected] = useState<string[]>([]); const cancelRef = useRef<HTMLButtonElement>(null);
  useEffect(() => { cancelRef.current?.focus(); const close = (event: KeyboardEvent) => { if (event.key === "Escape") cancel(); }; window.addEventListener("keydown", close); return () => window.removeEventListener("keydown", close); }, [cancel]);
  return <div className="modal-backdrop"><section className="holding-picker" role="dialog" aria-modal="true" aria-labelledby="holding-picker-title"><span className="confirm-kicker">首页卡片</span><h2 id="holding-picker-title">选择展示持仓</h2><p>勾选未展示的标的；确认后，选中 {selected.length} 张将替换当前末尾 {Math.min(selected.length, visibleIds.length)} 张。</p><div className="holding-picker-list">{holdings.map((item) => { const visible = visibleIds.includes(item.security_id); const checked = visible || selected.includes(item.security_id); return <label key={item.security_id} className={visible ? "is-visible" : ""}><input type="checkbox" checked={checked} disabled={visible || (!checked && selected.length >= limit)} onChange={(event) => setSelected((current) => event.target.checked ? [...current, item.security_id] : current.filter((id) => id !== item.security_id))} /><span><strong>{item.name}</strong><small className="mono">{item.symbol} · {assetLabel(item.asset_type)}</small></span><em>{visible ? "当前展示" : selected.includes(item.security_id) ? "待替换" : "可选择"}</em></label>; })}</div><div className="confirm-actions"><button ref={cancelRef} className="secondary" onClick={cancel}>取消</button><button disabled={!selected.length} onClick={() => apply(selected)}>确认替换 {selected.length} 张</button></div></section></div>;
}

function HoldingDeck({ holdings, openHolding, archiveDate }: { holdings: Holding[]; openHolding: (id: string) => void; archiveDate: string | null }) {
  const deckRef = useRef<HTMLDivElement>(null); const pointerDrag = useRef<{ sourceId: string; pointerId: number; startX: number; startY: number; active: boolean; lastTargetId: string | null } | null>(null); const suppressOpen = useRef(false); const [draggingId, setDraggingId] = useState<string | null>(null); const [limit, setLimit] = useState(3); const [pickerOpen, setPickerOpen] = useState(false); const [dismissedIds, setDismissedIds] = useState<string[]>([]); const [visibleIds, setVisibleIds] = useState<string[] | null>(() => { try { const saved = localStorage.getItem("holding-card-slots"); return saved ? JSON.parse(saved) : null; } catch { return null; } });
  useEffect(() => { if (!deckRef.current) return; const observer = new ResizeObserver(([entry]) => setLimit(cardLimitForWidth(entry.contentRect.width))); observer.observe(deckRef.current); return () => observer.disconnect(); }, []);
  useEffect(() => { setVisibleIds((current) => { const valid = (current ?? []).filter((id) => holdings.some((item) => item.security_id === id)).slice(0, limit); for (const item of holdings) if (valid.length < limit && !valid.includes(item.security_id)) valid.push(item.security_id); return valid; }); }, [holdings, limit]);
  useEffect(() => { if (visibleIds) localStorage.setItem("holding-card-slots", JSON.stringify(visibleIds)); }, [visibleIds]);
  const moveCard = (sourceId: string, targetId: string) => setVisibleIds((current) => { const next = [...(current ?? [])]; const source = next.indexOf(sourceId); const target = next.indexOf(targetId); if (source < 0 || target < 0 || source === target) return next; const [moved] = next.splice(source, 1); next.splice(target, 0, moved); return next; });
  const startPointerDrag = (event: React.PointerEvent<HTMLElement>, sourceId: string) => { if (event.button !== 0 || (event.target as HTMLElement).closest(".holding-card-remove")) return; event.currentTarget.setPointerCapture(event.pointerId); pointerDrag.current = { sourceId, pointerId: event.pointerId, startX: event.clientX, startY: event.clientY, active: false, lastTargetId: null }; };
  const movePointerDrag = (event: React.PointerEvent<HTMLElement>) => { const drag = pointerDrag.current; if (!drag || drag.pointerId !== event.pointerId) return; if (!drag.active && Math.hypot(event.clientX - drag.startX, event.clientY - drag.startY) < 6) return; if (!drag.active) { drag.active = true; setDraggingId(drag.sourceId); } event.preventDefault(); const targetId = document.elementFromPoint(event.clientX, event.clientY)?.closest<HTMLElement>(".holding-card")?.dataset.securityId; if (targetId && targetId !== drag.sourceId && targetId !== drag.lastTargetId) { moveCard(drag.sourceId, targetId); drag.lastTargetId = targetId; } };
  const finishPointerDrag = (event: React.PointerEvent<HTMLElement>) => { const drag = pointerDrag.current; if (!drag || drag.pointerId !== event.pointerId) return; if (event.currentTarget.hasPointerCapture(event.pointerId)) event.currentTarget.releasePointerCapture(event.pointerId); suppressOpen.current = drag.active; if (drag.active) window.setTimeout(() => { suppressOpen.current = false; }, 0); pointerDrag.current = null; setDraggingId(null); };
  const visible = (visibleIds ?? []).map((id) => holdings.find((item) => item.security_id === id)).filter((item): item is Holding => Boolean(item)); const unshown = holdings.filter((item) => !(visibleIds ?? []).includes(item.security_id)); const next = unshown.find((item) => !dismissedIds.includes(item.security_id)) ?? unshown[0];
  return <div className="holding-deck" ref={deckRef}><div className="holding-card-grid">{visible.map((item) => <article className={draggingId === item.security_id ? "holding-card dragging" : "holding-card"} data-security-id={item.security_id} key={item.security_id} onPointerDown={(event) => startPointerDrag(event, item.security_id)} onPointerMove={movePointerDrag} onPointerUp={finishPointerDrag} onPointerCancel={finishPointerDrag}><button className="holding-card-main" onClick={() => { if (suppressOpen.current) { suppressOpen.current = false; return; } openHolding(item.security_id); }}><span className="holding-card-code mono">{item.symbol}</span><strong title={item.name}>{item.name}</strong><span>{assetLabel(item.asset_type)} · 买入 {invested(item.invested_amount_cny)}</span><span className="holding-card-market"><b className={`mono ${tone(item.estimated_profit_cny)}`}>{item.estimated_profit_cny === null ? "暂不可估算" : money(item.estimated_profit_cny)}</b><i className={`mono ${tone(item.estimated_profit_percent)}`}>{percent(item.estimated_profit_percent)}</i></span><small className={item.trade_date !== archiveDate ? "stale-data" : ""}>{item.trade_date !== archiveDate ? `数据截至 ${day(item.trade_date)} · 当日未披露或无交易` : item.profit_basis ?? item.profit_reason ?? "等待盘后数据"}</small></button><button className="holding-card-drag" onKeyDown={(event) => { if (!event.altKey || !["ArrowLeft", "ArrowRight"].includes(event.key)) return; event.preventDefault(); const index = (visibleIds ?? []).indexOf(item.security_id); const target = (visibleIds ?? [])[index + (event.key === "ArrowLeft" ? -1 : 1)]; if (target) moveCard(item.security_id, target); }} aria-label={`拖动调整 ${item.symbol} 的顺序，或按 Option 加左右方向键`}>⠿</button><button className="holding-card-remove" onClick={() => { setVisibleIds((current) => (current ?? []).filter((id) => id !== item.security_id)); setDismissedIds((current) => [...new Set([...current, item.security_id])]); }} aria-label={`从首页移除 ${item.symbol}`}>移除</button></article>)}</div><div className="holding-deck-actions">{next && visible.length < limit && <button className="secondary" onClick={() => { setVisibleIds((current) => [...(current ?? []), next.security_id]); setDismissedIds((current) => current.filter((id) => id !== next.security_id)); }}>＋ 显示其他持仓</button>}{holdings.length > visible.length && <button className="secondary" onClick={() => setPickerOpen(true)}>选择展示持仓</button>}</div><p className="card-capacity">当前区域最多展示 {limit} 张；拖动整张卡片可调整顺序，移除不会删除持仓。</p>{pickerOpen && <HoldingPicker holdings={holdings} visibleIds={visibleIds ?? []} limit={limit} cancel={() => setPickerOpen(false)} apply={(selected) => { setVisibleIds((current) => replaceTrailingCards(current ?? [], selected, limit)); setDismissedIds((current) => current.filter((id) => !selected.includes(id))); setPickerOpen(false); }} />}</div>;
}

function ArchiveRail({ data }: { data: Bootstrap }) { return <div className="archive-rail"><span className="archive-label">盘后归档</span><strong className="mono">{day(data.report_as_of)}</strong><span>{data.archive_coverage.current}/{data.archive_coverage.total} 个标的已更新{data.archive_coverage.stale ? `，${data.archive_coverage.stale} 个当日无交易或未披露` : ""}</span><span className="archive-time">整理于 {data.refreshed_at ? new Date(data.refreshed_at).toLocaleString("zh-CN") : "等待首次归档"}</span></div>; }
function EmptyVault({ addHoldings }: { addHoldings: () => void }) { return <section className="empty-vault"><div className="empty-date mono">— —</div><h2>先添加你的持仓</h2><p>填写代码、类型、人民币买入金额和买入日期，应用会自动整理最近完整交易日的数据。</p><button onClick={addHoldings}>添加持仓</button></section>; }

function Today({ data, workspaces, addHoldings, navigate, openHolding }: { data: Bootstrap; workspaces: Record<string, Workspace>; addHoldings: () => void; navigate: (key: string) => void; openHolding: (id: string) => void }) {
  if (!data.holdings.length) return <><PageHeader eyebrow="今日复盘" title="持仓投资札记" description="围绕真实持仓保存盘后数据、公司资料和你的判断。" /><EmptyVault addHoldings={addHoldings} /></>;
  const calculable = data.holdings.filter((item) => item.estimated_profit_cny !== null); const profit = calculable.reduce((sum, item) => sum + (item.estimated_profit_cny ?? 0), 0); const materials = Object.values(workspaces).flatMap((item) => item.materials).sort((a, b) => b.published_at.localeCompare(a.published_at)).slice(0, 7); const notes = Object.values(workspaces).flatMap((item) => item.notes).sort((a, b) => (b.updated_at ?? b.created_at).localeCompare(a.updated_at ?? a.created_at)).slice(0, 3);
  const holdingById = Object.fromEntries(data.holdings.map((item) => [item.security_id, item]));
  return <><PageHeader eyebrow="今日复盘" title={`${day(data.report_as_of)} 持仓盘后记录`} description="先看持仓发生了什么，再决定需要写下什么。" /><ArchiveRail data={data} /><div className="today-layout"><Card title="组合盘后摘要" action={<button className="text-button" onClick={() => navigate("portfolio")}>查看账本</button>}><div className="summary-strip"><div><span>持仓标的</span><strong>{data.holdings.length}</strong></div><div><span>当前盈亏（估算）</span><strong className={`mono ${tone(calculable.length ? profit : null)}`}>{calculable.length ? money(profit) : "—"}</strong></div><div><span>可估算持仓</span><strong>{calculable.length}/{data.holdings.length}</strong></div></div><HoldingDeck holdings={data.holdings} openHolding={openHolding} archiveDate={data.report_as_of} /></Card><Card title="持仓事项" action={<span className="count-label">最近 {materials.length} 条</span>}>{materials.length ? <ul className="event-stream">{materials.map((item) => <li key={item.material_id}><time className="mono">{item.published_at}</time><div><Tag>{item.material_type}</Tag><a href={item.source_url} target="_blank" rel="noreferrer" onClick={(event) => followSource(event, item.source_url)}>{item.title}</a></div></li>)}</ul> : <p className="empty">最近没有已验证的持仓公告或财务报告。</p>}</Card><Card title="待复盘笔记" action={<button className="text-button" onClick={() => navigate("research")}>打开笔记</button>}>{notes.length ? <ul className="note-preview">{notes.map((item) => { const holding = holdingById[item.security_id]; return <li key={item.note_id}><div className="note-security"><strong>{holding?.name ?? "已删除持仓"}</strong><span className="mono">{holding?.symbol ?? symbolOf(item.security_id)}</span></div><span className="note-preview-body" title={item.body}>{item.body}</span><time>{new Date(item.updated_at ?? item.created_at).toLocaleDateString("zh-CN")}</time></li>; })}</ul> : <p className="empty">还没有投资笔记。</p>}</Card></div></>;
}

function Portfolio({ data, addHoldings, editHolding, deleteHolding, exportExcel }: { data: Bootstrap; addHoldings: () => void; editHolding: (entry: HoldingEntry) => void; deleteHolding: (entry: HoldingEntry) => void; exportExcel: () => void }) {
  const byId = Object.fromEntries(data.holdings.map((item) => [item.security_id, item]));
  return <><PageHeader eyebrow="持仓账本" title="我的持仓" description="每笔买入单独保存，可修订或删除；价格只取最近一次成功的盘后归档。" />{!data.holding_entries.length ? <EmptyVault addHoldings={addHoldings} /> : <Card title="持仓明细" action={<div className="button-row"><button className="secondary" onClick={addHoldings}>添加持仓</button><button onClick={exportExcel}>导出 Excel</button></div>}><div className="table-wrap"><table className="data-table holdings-table"><thead><tr><th>证券</th><th>类型</th><th className="numeric">买入金额</th><th>买入日期</th><th className="numeric">当前盈亏（估算）</th><th>数据日期</th><th>操作</th></tr></thead><tbody>{data.holding_entries.map((entry) => { const item = byId[entry.security_id]; return <tr key={entry.holding_id}><td><strong>{item?.name ?? symbolOf(entry.security_id)}</strong><small className="mono">{symbolOf(entry.security_id)}</small></td><td>{assetLabel(entry.asset_type)}</td><td className="numeric mono">{invested(entry.invested_amount_cny)}</td><td className="mono">{entry.bought_on}</td><td className={`numeric mono ${tone(entry.estimated_profit_cny)}`}>{entry.estimated_profit_cny === null ? (entry.profit_reason ?? "—") : <>{money(entry.estimated_profit_cny)} <small>{percent(entry.estimated_profit_percent)}</small></>}</td><td className="mono">{day(item?.trade_date ?? null)}</td><td><div className="row-actions"><button className="text-button" onClick={() => editHolding(entry)}>编辑</button><button className="text-button danger-text" onClick={() => deleteHolding(entry)}>删除</button></div></td></tr>; })}</tbody></table></div><p className="hint">盈亏按买入日收盘价估算，不代表实际成交成本；多笔同一证券的首页盈亏为合计值。</p></Card>}</>;
}

function MarketPage({ market }: { market: Market }) {
  const indices = market.indices; const lhb = market.lhb; const flow = market.industry_flow;
  return <><PageHeader eyebrow="市场盘后" title="A股市场概览" description="仅展示已完成交易日且日期可核验的盘后数据，不提供手动刷新。" /><div className="surface-grid"><Card title="大盘指数概览" action={indices && <span className="count-label">{indices.date} · {indices.source}</span>}>{indices?.rows.length ? <div className="index-grid">{indices.rows.map((row) => <div className="index-tile" key={row.code}><span>{row.name}</span><strong className="mono">{row.close.toLocaleString("zh-CN")}</strong><b className={`mono ${tone(row.change_percent)}`}>{percent(row.change_percent)}</b></div>)}</div> : <p className="empty">尚无日期校验通过的指数归档。</p>}</Card><Card title="龙虎榜" action={lhb && <span className="count-label">{lhb.date} · {lhb.source}</span>}>{lhb?.rows.length ? <div className="table-wrap"><table className="data-table"><thead><tr><th>证券</th><th className="numeric">涨跌幅</th><th className="numeric">买入额</th><th className="numeric">卖出额</th><th className="numeric">净额</th><th>上榜原因</th></tr></thead><tbody>{lhb.rows.map((row, index) => <tr key={`${row.symbol}-${index}`}><td><strong>{row.name}</strong><small className="mono">{row.symbol}</small></td><td className={`numeric mono ${tone(row.change_percent)}`}>{percent(row.change_percent)}</td><td className="numeric mono">{amountYi(row.buy_amount)}</td><td className="numeric mono">{amountYi(row.sell_amount)}</td><td className={`numeric mono ${tone(row.net_amount)}`}>{amountYi(row.net_amount)}</td><td>{row.reason}</td></tr>)}</tbody></table></div> : <p className="empty">该交易日无可核验龙虎榜记录，或来源暂不可用。</p>}</Card><Card title="行业资金流" action={flow && <span className="count-label">{flow.date} · {flow.source}</span>}>{flow ? <div className="flow-columns"><div><h3>净流入居前</h3>{flow.inbound.map((row) => <div className="flow-row" key={row.code}><span>{row.name}</span><strong className="mono up">{amountYi(row.net_amount)}</strong></div>)}</div><div><h3>净流出居前</h3>{flow.outbound.map((row) => <div className="flow-row" key={row.code}><span>{row.name}</span><strong className="mono down">{amountYi(row.net_amount)}</strong></div>)}</div></div> : <p className="empty">尚无带目标交易日时间戳的行业资金流归档。</p>}</Card></div></>;
}

function MaterialList({ materials, onExcerpt, type }: { materials: Material[]; onExcerpt: (item: Material) => void; type?: string }) { const rows = type ? materials.filter((item) => item.material_type === type) : materials; if (!rows.length) return <p className="empty">当前没有符合日期和证券代码校验的资料。</p>; return <><p className="count-label">显示最近 {Math.min(rows.length, 10)} 条，共归档 {rows.length} 条</p><ul className="material-list">{rows.slice(0, 10).map((item) => <li key={item.material_id}><div className="material-meta"><Tag>{item.material_type}</Tag><time className="mono">{item.published_at}</time></div><a href={item.source_url} target="_blank" rel="noreferrer" onClick={(event) => followSource(event, item.source_url)}>{item.title}</a><div className="material-actions"><span>{item.source_name}</span><button className="text-button" onClick={() => onExcerpt(item)}>摘录到笔记</button></div></li>)}</ul></>; }

function EditableNotes({ notes, edit, remove }: { notes: Note[]; edit: (note: Note, body: string) => Promise<void>; remove: (note: Note) => void }) {
  const [editing, setEditing] = useState<string | null>(null); const [body, setBody] = useState("");
  if (!notes.length) return <p className="empty">还没有笔记。</p>;
  return <ul className="note-list">{notes.map((item) => <li key={item.note_id}>{item.source_title && item.source_url && <a href={item.source_url} target="_blank" rel="noreferrer" onClick={(event) => followSource(event, item.source_url!)}>{item.source_title}</a>}{item.quoted_text && <blockquote className="quoted-text">{item.quoted_text}</blockquote>}{editing === item.note_id ? <div className="inline-editor"><textarea value={body} onChange={(event) => setBody(event.target.value)} /><div className="row-actions"><button disabled={!body.trim()} onClick={async () => { await edit(item, body); setEditing(null); }}>保存</button><button className="secondary" onClick={() => setEditing(null)}>取消</button></div></div> : <><p className="user-text">{item.body}</p><div className="item-footer"><time>{new Date(item.updated_at ?? item.created_at).toLocaleString("zh-CN")}</time><div className="row-actions"><button className="text-button" onClick={() => { setEditing(item.note_id); setBody(item.body); }}>编辑</button><button className="text-button danger-text" onClick={() => remove(item)}>删除</button></div></div></>}</li>)}</ul>;
}

function FinancialTable({ financials }: { financials: Financials | null }) { if (!financials?.periods.length) return <p className="empty">尚无已归档的结构化财务指标。</p>; return <><div className="table-wrap"><table className="data-table"><thead><tr><th>期间</th><th className="numeric">ROE</th><th className="numeric">毛利率</th><th className="numeric">资产负债率</th><th className="numeric">经营现金流</th><th className="numeric">自由现金流</th></tr></thead><tbody>{financials.periods.map((row) => <tr key={row.period}><td>{row.period_label}</td><td className="numeric mono">{percent(row.roe)}</td><td className="numeric mono">{percent(row.gross_margin)}</td><td className="numeric mono">{percent(row.debt_asset_ratio)}</td><td className="numeric mono">{amountYi(row.operating_cash_flow)}</td><td className="numeric mono">{amountYi(row.free_cash_flow)}</td></tr>)}</tbody></table></div><p className="hint">截止 {financials.cutoff_date} · {financials.source}<br />{financials.free_cash_flow_note}</p></>; }

function FundSecurity({ data, selected, workspace, setSelected, editNote, deleteNote }: { data: Bootstrap; selected: Holding; workspace?: Workspace; setSelected: (id: string) => void; editNote: (note: Note, body: string) => Promise<void>; deleteNote: (note: Note) => void }) {
  const fund = workspace?.fund; const latest = fund?.nav_history[0]; const events = fund?.nav_history.filter((item) => item.event) ?? [];
  return <><PageHeader eyebrow="基金资料" title={`${fund?.name ?? selected.name} ${selected.symbol}`} description="基金使用正式单位净值，不套用股票成交价、财报或公司公告模板。" /><div className="security-tabs" role="tablist">{data.holdings.map((item) => <button className={item.security_id === selected.security_id ? "secondary selected" : "secondary"} key={item.security_id} onClick={() => setSelected(item.security_id)}>{item.symbol}</button>)}</div><div className="price-hero fund-nav-hero"><div><span className="metric-label">最新单位净值</span><div className="price-main mono">{latest?.nav?.toFixed(4) ?? "尚未归档"}</div><div className={`price-change mono ${tone(latest?.change_percent ?? null)}`}>{percent(latest?.change_percent ?? null)} · {latest?.date ?? "等待净值日期"}</div></div><div className="price-meta"><span>当前盈亏（估算） <b className={`mono ${tone(selected.estimated_profit_cny)}`}>{money(selected.estimated_profit_cny)}</b></span><span>买入金额 {invested(selected.invested_amount_cny)}</span><span>截止 {fund?.cutoff_date ?? day(selected.trade_date)}</span></div></div><div className="fund-layout"><Card title="近期净值"><div className="table-wrap"><table className="data-table compact-table"><thead><tr><th>日期</th><th className="numeric">单位净值</th><th className="numeric">日涨跌</th></tr></thead><tbody>{fund?.nav_history.map((row) => <tr key={row.date}><td className="mono">{row.date}</td><td className="numeric mono">{row.nav.toFixed(4)}</td><td className={`numeric mono ${tone(row.change_percent)}`}>{percent(row.change_percent)}</td></tr>)}</tbody></table></div>{!fund?.nav_history.length && <p className="empty">尚无日期校验通过的基金净值。</p>}</Card><Card title="基金费用"><dl className="source-list"><div><dt>管理费</dt><dd>{fund?.fees.management_rate ?? "来源未披露"}</dd></div><div><dt>托管费</dt><dd>{fund?.fees.custodian_rate ?? "来源未披露"}</dd></div><div><dt>销售服务费</dt><dd>{fund?.fees.sales_service_rate ?? "来源未披露"}</dd></div></dl></Card><Card title="基金经理画像">{fund?.managers.length ? <ul className="manager-list">{fund.managers.map((manager) => <li key={manager.name}><strong>{manager.name}</strong><span>任职 {manager.work_time || "未披露"}</span><span>在管规模 {manager.managed_scale || "未披露"}</span><span>任期回报 <b className={`mono ${tone(manager.tenure_return_percent)}`}>{percent(manager.tenure_return_percent)}</b></span></li>)}</ul> : <p className="empty">尚无可核验的基金经理资料。</p>}</Card><Card title="近期事件">{events.length ? <ul className="event-stream">{events.map((row) => <li key={row.date}><time>{row.date}</time><span>{row.event}</span></li>)}</ul> : <p className="empty">近期净值记录中没有分红或份额调整事件。</p>}</Card><Card title="基金笔记"><EditableNotes notes={workspace?.notes ?? []} edit={editNote} remove={deleteNote} /></Card></div><p className="hint">{fund?.source ?? "基金公开资料尚未归档"}。基金经理指标用于资料整理，不构成评价或建议。</p></>;
}

function Security({ data, selected, workspace, setSelected, saveExcerpt, editNote, deleteNote }: { data: Bootstrap; selected: Holding; workspace?: Workspace; setSelected: (id: string) => void; saveExcerpt: (item: Material, quoted: string, body: string) => Promise<void>; editNote: (note: Note, body: string) => Promise<void>; deleteNote: (note: Note) => void }) {
  const [tab, setTab] = useState("overview"); const [material, setMaterial] = useState<Material | null>(null); const [quoted, setQuoted] = useState(""); const [body, setBody] = useState(""); const materials = workspace?.materials ?? []; const isHongKong = selected.asset_type === "hk_stock"; const financialReports = materials.filter((item) => item.material_type === "财务报告"); const openExcerpt = (item: Material) => { setMaterial(item); setQuoted(item.excerpt || item.title); setBody(""); };
  if (selected.asset_type === "fund") return <FundSecurity data={data} selected={selected} workspace={workspace} setSelected={setSelected} editNote={editNote} deleteNote={deleteNote} />;
  return <><PageHeader eyebrow="证券资料" title={`${selected.name} ${selected.symbol}`} description={isHongKong ? "港股使用盘后收盘价与香港交易所官方披露，不补造不可核验的结构化财务指标。" : "价格、财务事实、公开资料和你的判断分别保存。"} /><div className="security-tabs" role="tablist">{data.holdings.map((item) => <button className={item.security_id === selected.security_id ? "secondary selected" : "secondary"} key={item.security_id} onClick={() => setSelected(item.security_id)}>{item.symbol}</button>)}</div><div className="price-hero"><div><div className={`price-main mono ${tone(selected.estimated_profit_cny)}`}>{selected.estimated_profit_cny === null ? "暂不可估算" : money(selected.estimated_profit_cny)}</div><div className={`price-change mono ${tone(selected.estimated_profit_percent)}`}>{percent(selected.estimated_profit_percent)} · 当前盈亏（估算）</div></div><div className="price-meta"><span>收盘日 {day(selected.trade_date)}</span><span>买入金额 {invested(selected.invested_amount_cny)}</span><span>买入日期 {selected.bought_on ?? "—"}</span><span>{selected.profit_basis ?? selected.profit_reason ?? selected.valuation_status}</span></div></div><div className="detail-tabs" role="tablist">{[["overview", "盘后概览"], ["financials", isHongKong ? "财务披露" : "财务数据"], ["materials", "公告资料"], ["notes", "我的笔记"]].map(([key, label]) => <button key={key} className={tab === key ? "selected" : "secondary"} onClick={() => setTab(key)}>{label}</button>)}</div>{tab === "overview" && <Card title="本次归档"><dl className="source-list"><div><dt>收盘价</dt><dd className="mono">{money(selected.price)}</dd></div><div><dt>当日涨跌</dt><dd className={`mono ${tone(selected.change_percent)}`}>{percent(selected.change_percent)}</dd></div><div><dt>数据日期</dt><dd className="mono">{day(selected.trade_date)}</dd></div><div><dt>盈亏口径</dt><dd>{selected.profit_basis ?? selected.profit_reason ?? "—"}</dd></div></dl></Card>}{tab === "financials" && (isHongKong ? <div className="surface-grid"><Card title="港股披露概览"><dl className="source-list"><div><dt>最近披露</dt><dd className="mono">{materials[0]?.published_at ?? "尚未归档"}</dd></div><div><dt>业绩及财务报告</dt><dd>{financialReports.length} 条</dd></div><div><dt>已归档官方披露</dt><dd>{materials.length} 条</dd></div><div><dt>来源</dt><dd>香港交易所披露易</dd></div></dl><p className="hint">以上为官方披露的日期与数量摘要，不将非结构化 PDF 推算成 ROE、毛利率等数值。</p></Card><Card title="业绩与财务报告原文"><MaterialList materials={materials} type="财务报告" onExcerpt={openExcerpt} /></Card></div> : <div className="surface-grid"><Card title="历史财务数据"><FinancialTable financials={workspace?.financials ?? null} /></Card><Card title="财务报告原文"><MaterialList materials={materials} type="财务报告" onExcerpt={openExcerpt} /></Card></div>)}{tab === "materials" && <Card title={isHongKong ? "港交所公司公告" : "公司公告"}><MaterialList materials={materials.filter((item) => item.material_type !== "财务报告")} onExcerpt={openExcerpt} /></Card>}{tab === "notes" && <Card title="证券笔记"><EditableNotes notes={workspace?.notes ?? []} edit={editNote} remove={deleteNote} /></Card>}{material && <div className="excerpt-panel" role="dialog" aria-modal="true"><div className="excerpt-head"><div><span>摘录资料</span><strong>{material.title}</strong><a href={material.source_url} target="_blank" rel="noreferrer" onClick={(event) => followSource(event, material.source_url)}>查看原文</a></div><button className="text-button" onClick={() => setMaterial(null)}>关闭</button></div><p className="hint">保存后，原文标题和链接会随摘录一同保留在笔记中。</p><label>摘录内容<textarea value={quoted} onChange={(event) => setQuoted(event.target.value)} /></label><label>我的判断<textarea value={body} onChange={(event) => setBody(event.target.value)} /></label><button disabled={!quoted.trim() || !body.trim()} onClick={async () => { await saveExcerpt(material, quoted, body); setMaterial(null); }}>保存到笔记</button></div>}</>;
}

function Research({ data, workspaces, selected, setSelected, saveNote, editNote, deleteNote }: { data: Bootstrap; workspaces: Record<string, Workspace>; selected?: Holding; setSelected: (id: string) => void; saveNote: (body: string) => Promise<void>; editNote: (note: Note, body: string) => Promise<void>; deleteNote: (note: Note) => void }) {
  const [note, setNote] = useState(""); if (!selected) return <><PageHeader eyebrow="投资笔记" title="我的复盘记录" description="添加持仓后，可以为每只证券或基金保存复盘笔记。" /><p className="empty">当前没有持仓证券。</p></>; const workspace = workspaces[selected.security_id];
  return <><PageHeader eyebrow="投资笔记" title="我的复盘记录" description="按持仓保存观察、问题和下一次需要核对的事项。" /><div className="security-tabs">{data.holdings.map((item) => <button className={item.security_id === selected.security_id ? "secondary selected" : "secondary"} key={item.security_id} onClick={() => setSelected(item.security_id)}>{item.name}</button>)}</div><div className="surface-grid"><Card title="添加复盘笔记"><div className="form-row"><textarea value={note} onChange={(event) => setNote(event.target.value)} placeholder="记录观察、问题或下一次复核事项…" /><button disabled={!note.trim()} onClick={async () => { await saveNote(note); setNote(""); }}>保存笔记</button></div></Card><Card title="最近笔记"><EditableNotes notes={workspace?.notes ?? []} edit={editNote} remove={deleteNote} /></Card></div></>;
}

function DataPage({ data, download }: { data: Bootstrap; download: (url: string, kind: "markdown" | "backup") => void }) { return <><PageHeader eyebrow="数据与备份" title="本地数据管理" description="进入应用时检查一次盘后归档；若应用持续打开，会在每日 17:31 再检查一次。" /><ArchiveRail data={data} /><div className="surface-grid"><Card title="自动归档规则"><dl className="source-list"><div><dt>盘前与盘中</dt><dd>显示上一交易日盘后数据</dd></div><div><dt>首次进入盘后</dt><dd>当天缺少归档时自动整理，不提供手动刷新</dd></div><div><dt>失败处理</dt><dd>保留上一次成功归档，不补零</dd></div><div><dt>联网范围</dt><dd>持仓证券、基金资料及固定的市场盘后栏目</dd></div></dl></Card><Card title="研究笔记"><p>导出包含当前复盘笔记、资料摘录和数据截止时间。</p><button onClick={() => download("/api/exports/research.md", "markdown")}>导出 Markdown</button></Card><Card title="完整备份"><p>包含本地数据库、盘后快照、资料、附件和校验和。</p><button onClick={() => download("/api/exports/backup.zip", "backup")}>创建完整备份</button></Card></div></>; }

function ConfirmDelete({ request, busy, cancel, confirmDelete }: { request: DeleteRequest; busy: boolean; cancel: () => void; confirmDelete: () => void }) {
  const cancelRef = useRef<HTMLButtonElement>(null);
  useEffect(() => {
    cancelRef.current?.focus();
    const closeOnEscape = (event: KeyboardEvent) => { if (event.key === "Escape" && !busy) cancel(); };
    window.addEventListener("keydown", closeOnEscape);
    return () => window.removeEventListener("keydown", closeOnEscape);
  }, [busy, cancel]);
  return <div className="modal-backdrop"><section className="confirm-dialog" role="alertdialog" aria-modal="true" aria-labelledby="confirm-delete-title"><span className="confirm-kicker">删除确认</span><h2 id="confirm-delete-title">确认删除{request.kind === "holding" ? "这笔持仓" : "这条笔记"}？</h2><p>{request.label}</p><p className="hint">删除后当前页面不再显示，但本地修订历史仍会保留。</p><div className="confirm-actions"><button ref={cancelRef} className="secondary" disabled={busy} onClick={cancel}>取消</button><button className="danger-button" disabled={busy} onClick={confirmDelete}>{busy ? "正在删除…" : "确认删除"}</button></div></section></div>;
}

export function App() {
  const [active, setActive] = useState("today"); const [data, setData] = useState<Bootstrap | null>(null); const [workspaces, setWorkspaces] = useState<Record<string, Workspace>>({}); const [selectedId, setSelectedId] = useState(""); const [busy, setBusy] = useState(false); const [message, setMessage] = useState("正在读取本地投资资料…"); const [editorOpen, setEditorOpen] = useState(false); const [editingEntry, setEditingEntry] = useState<HoldingEntry | null>(null); const [deleteRequest, setDeleteRequest] = useState<DeleteRequest | null>(null);
  const load = async () => { const next = await api<Bootstrap>("/api/bootstrap"); setData(next); setSelectedId((current) => next.holdings.some((item) => item.security_id === current) ? current : next.holdings[0]?.security_id || ""); const pairs = await Promise.all(next.holdings.map(async (item) => [item.security_id, await api<Workspace>(`/api/research/${item.security_id}`)] as const)); setWorkspaces(Object.fromEntries(pairs)); setMessage(next.holdings.length ? `已归档 ${day(next.report_as_of)}（${next.archive_coverage.current}/${next.archive_coverage.total} 个标的已更新）` : "本地资料库为空，可添加持仓开始使用"); };
  useEffect(() => { load().catch((error) => setMessage(`本地服务不可用：${error.message}`)); let lastCheck = Date.now(); const automaticCheck = () => { if (document.visibilityState !== "visible" || Date.now() - lastCheck < 60_000) return; lastCheck = Date.now(); load().catch((error) => setMessage(`自动盘后归档未完成：${error.message}`)); }; window.addEventListener("focus", automaticCheck); document.addEventListener("visibilitychange", automaticCheck); const now = new Date(); const next = new Date(now); next.setHours(17, 31, 0, 0); if (next <= now) next.setDate(next.getDate() + 1); let dailyTimer: number | undefined; const firstTimer = window.setTimeout(() => { load().catch((error) => setMessage(`自动盘后归档未完成：${error.message}`)); dailyTimer = window.setInterval(() => load().catch((error) => setMessage(`自动盘后归档未完成：${error.message}`)), 24 * 60 * 60 * 1000); }, next.getTime() - now.getTime()); return () => { window.removeEventListener("focus", automaticCheck); document.removeEventListener("visibilitychange", automaticCheck); window.clearTimeout(firstTimer); if (dailyTimer) window.clearInterval(dailyTimer); }; }, []);
  const run = async (task: () => Promise<void>, pending: string, done: string) => { setBusy(true); setMessage(pending); try { await task(); setMessage(done); } catch (error) { setMessage(`操作失败：${error instanceof Error ? error.message : String(error)}`); } finally { setBusy(false); } };
  const selected = data?.holdings.find((item) => item.security_id === selectedId) ?? data?.holdings[0];
  const saveHoldings = (rows: HoldingDraft[]) => run(async () => { await api("/api/holdings", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ rows }) }); await load(); setEditorOpen(false); }, "正在保存持仓…", "持仓已保存");
  const saveHoldingEdit = (rows: HoldingDraft[]) => run(async () => { if (!editingEntry) return; await api(`/api/holdings/${encodeURIComponent(editingEntry.holding_id)}`, { method: "PUT", headers: { "Content-Type": "application/json" }, body: JSON.stringify(rows[0]) }); await load(); setEditingEntry(null); }, "正在保存修订…", "持仓已修订");
  const deleteHolding = (entry: HoldingEntry) => setDeleteRequest({ kind: "holding", entry, label: `${symbolOf(entry.security_id)} · 买入金额 ${invested(entry.invested_amount_cny)} · ${entry.bought_on}` });
  const saveNote = (body: string) => run(async () => { if (!selected) throw new Error("没有可关联的证券"); await api("/api/research/notes", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ security_id: selected.security_id, body }) }); await load(); }, "正在保存笔记…", "笔记已保存");
  const editNote = (note: Note, body: string) => run(async () => { await api(`/api/research/notes/${note.note_id}`, { method: "PUT", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ security_id: note.security_id, body }) }); await load(); }, "正在修订笔记…", "笔记已修订");
  const deleteNote = (note: Note) => setDeleteRequest({ kind: "note", note, label: note.body.length > 90 ? `${note.body.slice(0, 90)}…` : note.body });
  const confirmDelete = () => { if (!deleteRequest) return; void run(async () => { if (deleteRequest.kind === "holding") await api(`/api/holdings/${encodeURIComponent(deleteRequest.entry.holding_id)}`, { method: "DELETE" }); else await api(`/api/research/notes/${deleteRequest.note.note_id}`, { method: "DELETE" }); setDeleteRequest(null); await load(); }, deleteRequest.kind === "holding" ? "正在删除持仓…" : "正在删除笔记…", deleteRequest.kind === "holding" ? "持仓已删除" : "笔记已删除"); };
  const saveExcerpt = (item: Material, quoted_text: string, body: string) => run(async () => { await api("/api/research/notes/from-material", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ security_id: item.security_id, material_id: item.material_id, quoted_text, body }) }); await load(); }, "正在保存资料摘录…", "资料已摘录到笔记");
  const saveExport = async (url: string, kind: "xlsx" | "markdown" | "backup", suggestedName: string) => { const response = await fetch(url); if (!response.ok) throw new Error("导出文件生成失败"); const raw = new Uint8Array(await response.arrayBuffer()); const bytes = Array.from(raw); if ((window as unknown as { __TAURI_INTERNALS__?: object }).__TAURI_INTERNALS__) return invoke<string | null>("save_export", { bytes, suggestedName, kind }); const extension = kind === "markdown" ? "md" : kind === "backup" ? "zip" : "xlsx"; const anchor = document.createElement("a"); anchor.href = URL.createObjectURL(new Blob([raw])); anchor.download = `${suggestedName}.${extension}`; anchor.click(); URL.revokeObjectURL(anchor.href); return suggestedName; };
  const exportExcel = () => run(async () => { await saveExport("/api/holdings/export.xlsx", "xlsx", `我的持仓-${new Date().toISOString().slice(0, 10)}`); }, "正在生成 Excel…", "如已选择位置，Excel 已保存");
  const download = (url: string, kind: "markdown" | "backup") => void run(async () => { await saveExport(url, kind, `${kind === "markdown" ? "投资笔记" : "投资札记完整备份"}-${new Date().toISOString().slice(0, 10)}`); }, "正在生成导出文件…", "如已选择位置，文件已保存");
  const addHoldings = () => { setEditingEntry(null); setEditorOpen(true); }; const openHolding = (id: string) => { setSelectedId(id); setActive("security"); };
  let content: React.ReactNode = <div className="loading-panel">{message}</div>;
  if (data) { if (editingEntry) { const summary = data.holdings.find((item) => item.security_id === editingEntry.security_id); content = <HoldingEditor editing initialRows={[{ row_id: editingEntry.holding_id, symbol: summary?.symbol ?? symbolOf(editingEntry.security_id), asset_type: editingEntry.asset_type, invested_amount_cny: editingEntry.invested_amount_cny, bought_on: editingEntry.bought_on }]} save={saveHoldingEdit} cancel={() => setEditingEntry(null)} />; } else if (editorOpen) content = <HoldingEditor save={saveHoldings} cancel={() => setEditorOpen(false)} />; else if (active === "today") content = <Today data={data} workspaces={workspaces} addHoldings={addHoldings} navigate={setActive} openHolding={openHolding} />; else if (active === "market") content = <MarketPage market={data.market} />; else if (active === "portfolio") content = <Portfolio data={data} addHoldings={addHoldings} editHolding={setEditingEntry} deleteHolding={deleteHolding} exportExcel={() => void exportExcel()} />; else if (active === "security") content = selected ? <Security data={data} selected={selected} workspace={workspaces[selected.security_id]} setSelected={setSelectedId} saveExcerpt={saveExcerpt} editNote={editNote} deleteNote={deleteNote} /> : <><PageHeader eyebrow="证券资料" title="持仓公司资料" description="添加持仓后归档财务、公告和笔记。" /><EmptyVault addHoldings={addHoldings} /></>; else if (active === "research") content = <Research data={data} workspaces={workspaces} selected={selected} setSelected={setSelectedId} saveNote={saveNote} editNote={editNote} deleteNote={deleteNote} />; else content = <DataPage data={data} download={download} />; }
  const topbar = active === "today" ? ["今日复盘", day(data?.report_as_of ?? null)] : active === "market" ? ["市场盘后", day(data?.market.indices?.date ?? null)] : active === "portfolio" ? ["持仓账本", `${data?.holding_entries.length ?? 0} 笔`] : active === "security" ? [selected?.asset_type === "fund" ? "基金资料" : "证券资料", selected?.symbol ?? "未选择"] : active === "research" ? ["投资笔记", selected?.name ?? "未选择"] : ["数据与备份", "仅在本机保存"];
  const navigate = (key: string) => { setActive(key); setEditorOpen(false); setEditingEntry(null); setMessage(data?.holdings.length ? `已归档 ${day(data.report_as_of)}（${data.archive_coverage.current}/${data.archive_coverage.total} 个标的已更新）` : "本地资料库为空，可添加持仓开始使用"); };
  return <div className="app-shell"><a className="skip-link" href="#content">跳转到主要内容</a><aside className="sidebar"><div className="brand"><span className="brand-mark">记</span><span>投资札记</span></div><nav aria-label="主要导航">{navItems.map((item) => <button key={item.key} className={active === item.key ? "nav-active" : ""} onClick={() => navigate(item.key)}>{item.label}</button>)}</nav><div className="side-foot"><span className="local-dot">● 仅在本机保存</span><span>版本 0.1.9</span></div></aside><main id="content"><div className="topbar"><div className="topbar-crumb"><span>{topbar[0]}</span><span className="topbar-divider">/</span><span>{topbar[1]}</span></div><div className="automatic-state"><span className="local-dot">●</span> 每日盘后自动归档</div></div><div className="status-line" role="status">{busy ? "处理中｜" : ""}{message}</div>{content}</main><aside className="attention" aria-label="今日待办"><div className="attention-header"><h2>今日待办</h2></div><ul className="attention-list"><li><Tag>数据日期</Tag><span>{day(data?.report_as_of ?? null)}</span></li><li><Tag>持仓资料</Tag><span>{Object.values(workspaces).reduce((sum, item) => sum + item.materials.length, 0)} 条已归档</span></li><li><Tag tone="warning">最近笔记</Tag><span>{Object.values(workspaces).reduce((sum, item) => sum + item.notes.length, 0)} 条</span></li></ul></aside>{deleteRequest && <ConfirmDelete request={deleteRequest} busy={busy} cancel={() => setDeleteRequest(null)} confirmDelete={confirmDelete} />}</div>;
}
